/**
 * UDC onload
 */
scwin.onUdcCompleted = function () {
  scwin.set_popupData();
  const vCurDate = $c.date.getServerDateTime($p, "yyyyMMdd"); // 서버를 기준으로 현재 날짜 반환

  ed_operDd.setValue(vCurDate);
  ed_qryDt1.setValue(vCurDate);
  ed_qryDt1.setValue(vCurDate);

  // 샤시번호 위치
  udc_chassisVehclNo._wqContent.scope.grp_group.setStyle("left", "-220px");
};

/**
 * 화면 데이터 세팅
 */
scwin.set_popupData = function () {
  const {
    cCase,
    pFrame,
    sFrame
  } = $c.data.getParameter($p);
  const topFrame = opener.$p.getComponentById(pFrame).scope;
  const btmFrame = opener.$p.getComponentById(sFrame).scope;
  var lclRow = topFrame.scwin.selectedLclRow; // 선택된 화물정보
  var vehclRow = topFrame.scwin.selectedvehclRow; // 선택된 차량정보
  var flType = topFrame.scwin.CargoType; // 화물종류(벌크,컨테이너)		
  var vehclType = topFrame.scwin.vehclType; // 차량종류

  let dlt_bottom;
  switch (vehclType) {
    case 'all':
      dlt_bottom = btmFrame.dtl_car;
      break;
    case 'blk':
      dlt_bottom = btmFrame.dtl_car_blk;
      break;
    case 'cntr':
      dlt_bottom = btmFrame.dtl_car_cntr;
      break;
    case 'matching':
      dlt_bottom = btmFrame.dtl_car_matching;
      break;
    case 'mb':
      dlt_bottom = btmFrame.dtl_car_mb;
      break;
    case 'public':
      dlt_bottom = btmFrame.dtl_openPublic;
      break;
  }
  if (dlt_bottom.getCellData(vehclRow, "maxShipwgtVol") != 0) {
    // 2026.03.11
    // ds_fl / ds_flc 2개인데, ds_fl만 사용하는건 이상해보임
    if (dlt_bottom.getCellData(vehclRow, "maxShipwgtVol") * 1.1 < topFrame.ds_fl.getCellData(lclRow, "wt")) $c.win.alert($p, "[TMS오류] 차량의 최대적재량을 초과하였습니다");
  }

  // 화물정보 그리드 그리기
  scwin.f_blkGrid(flType);
  const dlt_fl = topFrame.ds_fl;
  const dlt_flc = topFrame.ds_flc;
  if (flType == 'cargo') {
    // 벌크 화물

    // 대표거래처가 000012인 경우
    if (dlt_fl.getCellData(lclRow, "repClntNo") == "000012") {
      grp_cond1.setStyle("display", "");
      grp_cond2.setStyle("display", "");
      grp_cond3.setStyle("display", "");
      grp_cond4.setStyle("display", "");
      grp_cond5.setStyle("display", "none");
    }

    // 동일 합적번호 배열
    const dmCoshippingNo = dlt_fl.getCellData(lclRow, "dmCoshippingNo");
    const matchArr = dlt_fl.getMatchedIndex("dmCoshippingNo", dmCoshippingNo, true);
    if (matchArr.length > 0) {
      for (let i = 0; i < matchArr.length; i++) {
        // 배차된 화물인지 체크
        const statuss = dlt_fl.getCellData(matchArr[i], "statuss");
        if (statuss != "대기") {
          $c.win.alert($p, '[TMS오류]배차된 화물을 다시 배차 하실 수 없습니다. 확인 바랍니다.').then(() => {
            window.close();
          });
          return;
        }

        // 그리드 dataList에 set 해주는 함수
        // scwin.f_SetFlDtlInfo('cargo', matchArr[i]);
      }
      ds_fl.setJSON(dlt_fl.getMatchedJSON("dmCoshippingNo", dmCoshippingNo, true));
    } else {
      ds_fl.setJSON([dlt_fl.getRowJSON(lclRow)]);
    }

    // 출도착관련정보 세팅
    // 실상차 중량
    if (ds_fl.getCellData(0, "realOnWt") != 0) {
      ed_onWt_blk.setValue(ds_fl.getCellData(lclRow, "wt"));
    } else {
      // 중량의 합계로 대처
      ed_onWt_blk.setValue(ds_fl.getColSum("wt"));
    }
    // 실상차 수량
    if (ds_fl.getCellData(0, "realOnQty") != 0) {
      ed_onQty_blk.setValue(ds_fl.getCellData(0, "realOnQty"));
    } else {
      // 수량의 합계로 대처
      ed_onQty_blk.setValue(ds_fl.getColSum("qty"));
    }
  } else if (flType == 'cont') {
    // 컨테이너 화물

    // 대표거래처가 000012인 경우
    if (dlt_fl.getCellData(lclRow, "repClntNo") == "000012") {
      grp_cond1.setStyle("display", "");
      grp_cond2.setStyle("display", "");
      grp_cond3.setStyle("display", "none");
      grp_cond4.setStyle("display", "none");
      grp_cond5.setStyle("display", "");
    }

    // as-is는 RowMark가 1인 row를 for문 돌면서 찾아서 하는데, 어차피 컨테이너는 클릭한 row가 RowMark 1이 됨
    // 벌크화물처럼 동일한 합적번호를 찾아서 RowMark를 주고 있지 않음
    // 배차된 화물인지 체크
    if (dlt_flc.getCellData(lclRow, "statuss") != "대기") {
      $c.win.alert($p, '[TMS오류]배차된 화물을 다시 배차 하실 수 없습니다. 확인 바랍니다.').then(() => {
        window.close();
      });
      return;
    }

    // scwin.f_SetFlDtlInfo('cont', lclRow);
    ds_flc.setJSON([dlt_flc.getRowJSON(lclRow)]);
  }

  // 부모화면부터 없으면 팝업을 호출할 수 없음
  if ($c.util.isEmpty($p, vehclRow)) {
    $c.win.alert($p, '차량정보가선택되지 않았습니다. 차량정보를 선택하여 주시기 바랍니다.').then(() => {
      window.close();
    });
    return;
  }

  // 차량정보
  // 차량번호 / 등록일자 / 기사성명 / 휴대전화 / 차량종류 / 차량톤수 / 현재위치 / 스마트폰전송여부
  const {
    vehclNo,
    ...rest
  } = dlt_bottom.getRowJSON(vehclRow);
  ed_vehclNo.setValue(vehclNo);
  ed_regDd.setValue(rest.mtvehclRegDt.replace(/-/g, ''));
  ed_drvNm.setValue(rest.picNm);
  ed_moTel.setValue(rest.handphoneNo);
  ed_vehclCls.setValue(rest.typeCdNm);
  ed_vehclTon.setValue(rest.tonCdNm);
  ed_vehclPos.setValue(rest.posTxt);
  chk_pda.setValue(rest.pdaNo != "" ? "1" : "");

  // 대표거래처가 000012인 경우 - grp_cond1의 실상차일시 시간 세팅
  const now = new Date();
  now.setHours(now.getHours() + 1);
  const hh = String(now.getHours()).padStart(2, "0");
  const mm = String(now.getMinutes() < 10 ? 10 : now.getMinutes()).padStart(2, "0");
  ed_onDt_blk.setValue(`${hh}${mm}`);

  // 보랄 배차 회전수 확인
  // 대표거래처가 000001인 경우
  if (dlt_fl.getCellData(lclRow, "repClntNo") == "000001") {
    scwin.f_RestrictiveAllocate();
  }
};

/**
 * 벌크/컨테이너 화물정보 그리드 + 대표거래처가 000012인 경우 table setting
 */
scwin.f_blkGrid = function (str) {
  if (str == "cargo") {
    grp_cargo.setStyle('display', 'block');
    grp_cont.setStyle('display', 'none');
    tbx_vehclNo.removeClass("req");
  } else {
    grp_cargo.setStyle('display', 'none');
    grp_cont.setStyle('display', 'block');
    tbx_vehclNo.addClass("req");
  }
  ;
  grp_cond1.setStyle("display", "none");
  grp_cond2.setStyle("display", "none");
  grp_cond3.setStyle("display", "none");
  grp_cond4.setStyle("display", "none");
  grp_cond5.setStyle("display", "none");
};

/**
 * 보랄 배차 한정 동일 차량이 이틀 연속 3회/일 이상 배차 시, 차량 1대가 13회/주 배차 시 Alert 
 */
scwin.f_RestrictiveAllocate = async function () {
  ds_CarNo.set('carNo', ed_vehclNo.getValue().substr(5, 4));
  const rtn = await $c.sbm.execute($p, sbm_retrieveRestrictiveAllocate);
  if (rtn.responseJSON.resultDataSet[0].Code == 0) {
    if (ds_AllocateCnt.getTotalRow() > 0) {
      if (ds_AllocateCnt.getCellData(0, "twoDaysAllocateCnt") >= 3) $c.win.alert($p, "일 배차 기준 초과입니다. 공장 출하팀과 협의 바랍니다.");else if (ds_AllocateCnt.getCellData(0, "weekdayAllocateCnt") >= 13) $c.win.alert($p, "주 배차 기준 초과입니다. 공장 출하팀과 협의 바랍니다.");
    }
  }
};

/**
 * 팝업 닫기 
 */
scwin.btn_close_onclick = function (e) {
  window.close();
};

/**
 * [배차]
 */
scwin.f_ApplyAlloccar = async function (e) {
  const {
    cCase,
    pFrame,
    sFrame
  } = $c.data.getParameter($p);
  const topFrame = opener.$p.getComponentById(pFrame).scope;
  const btmFrame = opener.$p.getComponentById(sFrame).scope;
  var lclRow = topFrame.scwin.selectedLclRow; // 선택된 화물정보
  var vehclRow = topFrame.scwin.selectedvehclRow; // 선택된 차량정보
  var flType = topFrame.scwin.CargoType; // 화물종류(벌크,컨테이너)		
  var vehclType = topFrame.scwin.vehclType; // 차량종류

  let dlt_bottom;
  var vOpenFlag; // 배차구분 : 1.배차, 2.용차    
  var vFlFlag; // 화물구분 : 1.벌크, 2.컨테이너
  var vOperDate; // 배차일자(실제 배차되는 일자)
  var vVehclIdx; // 공차등록된 차량 idx
  var vFlIdxs; // 선택된 화물 idx
  var vRentClntIdx; // 용차사 idx(거래처)
  var vRentVehclIdx; // 용차 idx (차량)
  var vVehclDate; // 공차등록일
  var vRmk; // 비고
  var vUserId; // 사용자 아이디

  // 현재 화면은 배차 화면
  vOpenFlag = '1';

  // 화물구분     
  if (flType == 'cargo') {
    vFlFlag = '1';
  } else {
    vFlFlag = '2';
  }
  ;

  // 배차일자 (실제 배차되는 일자)
  vOperDate = ed_operDd.getValue();

  // 공차등록된 차량 IDX
  switch (vehclType) {
    case 'all':
      dlt_bottom = btmFrame.dtl_car;
      break;
    case 'blk':
      dlt_bottom = btmFrame.dtl_car_blk;
      break;
    case 'cntr':
      dlt_bottom = btmFrame.dtl_car_cntr;
      break;
    case 'matching':
      dlt_bottom = btmFrame.dtl_car_matching;
      break;
    case 'mb':
      dlt_bottom = btmFrame.dtl_car_mb;
      break;
    case 'public':
      dlt_bottom = btmFrame.dtl_openPublic;
      break;
    default:
      $c.win.alert($p, '배차를 할 수 있는 차량이 아닙니다.').then(() => {
        return;
      });
      break;
  }
  vVehclIdx = dlt_bottom.getCellData(vehclRow, "ez110Idx").toString();

  // 선택된 화물 idx
  vFlIdxs = '';
  if (vFlFlag == '1') {
    // 벌크화물
    for (let i = 0; i < ds_fl.getTotalRow(); i++) {
      vFlIdxs += ds_fl.getCellData(i, "idx") + ",";
    }
  } else {
    // 컨테이너
    vFlIdxs = ds_flc.getCellData(0, "idx") + ',';
  }
  vFlIdxs = vFlIdxs.substring(0, vFlIdxs.length - 1); // 쉼표 제거

  vRentClntIdx = ''; // 용차사 IDX (현재 화면은 배차 화면 이므로 '')
  vRentVehclIdx = ''; // 용차 IDX (현재 화면은 배차 화면이므로 '')
  vVehclDate = ed_regDd.getValue(); // 공차등록일
  vRmk = ''; // 비고
  vUserId = $c.data.getMemInfo($p, "userId"); // 사용자

  if ($c.gus.cfGetByteLength($p, scwin.chassisVehclNo) > 12) {
    $c.win.alert($p, "차량번호는 한글6자리까지 입력 가능합니다.");
    return;
  }
  if ($c.util.isEmpty($p, vOperDate)) {
    $c.win.alert($p, "배차일자는 필수 입니다.").then(() => {
      ed_operDd.focus();
    });
    return;
  }

  // 컨테이너일때만 필수체크
  if (flType == "cont") {
    if ($c.gus.cfGetByteLength($p, scwin.chassisVehclNo) == 0) {
      $c.win.alert($p, "샤시번호는 필수 입니다.").then(() => {
        udc_chassisVehclNo._wqContent.scope.ed_input.focus();
      });
      return;
    }
  }
  ds_ApplyAlloccar.removeAll();
  ds_ApplyAlloccar.reform();

  // 데이터 입력
  const loop = vFlIdxs.replaceAll("-", ",").split(",");
  for (let i = 0; i < loop.length; i += 2) {
    let iRow = ds_ApplyAlloccar.insertRow();
    ds_ApplyAlloccar.setCellData(iRow, "operFlag", vOpenFlag);
    ds_ApplyAlloccar.setCellData(iRow, "flFlag", vFlFlag);
    ds_ApplyAlloccar.setCellData(iRow, "operDate", vOperDate);
    ds_ApplyAlloccar.setCellData(iRow, "vehclIdx", String(vVehclIdx));
    ds_ApplyAlloccar.setCellData(iRow, "flIdxs", loop[i]);
    ds_ApplyAlloccar.setCellData(iRow, "flDtlIdxs", loop[i + 1]);
    ds_ApplyAlloccar.setCellData(iRow, "rentClntIdx", vRentClntIdx);
    ds_ApplyAlloccar.setCellData(iRow, "rentVehclIdx", vRentVehclIdx);
    ds_ApplyAlloccar.setCellData(iRow, "vehclDate", vVehclDate);
    ds_ApplyAlloccar.setCellData(iRow, "rmk", vRmk);
    ds_ApplyAlloccar.setCellData(iRow, "userId", vUserId);
    ds_ApplyAlloccar.setCellData(iRow, "ez124Idx", scwin.chassisVehclNoHidden); // 샤시등록번호
    ds_ApplyAlloccar.setCellData(iRow, "chassisEqCd", scwin.chassisEqCd); // 샤시장비코드
    ds_ApplyAlloccar.setCellData(iRow, "chassisEqKndCd", scwin.chassisEqKndCd); // 샤시종류코드
    ds_ApplyAlloccar.setCellData(iRow, "chassisVehclNo", scwin.chassisVehclNo); // 샤시차량번호
    ds_ApplyAlloccar.setCellData(iRow, "vehclNo2", ed_vehclNo.getValue());
    ds_ApplyAlloccar.setCellData(iRow, "arvDt2", ed_qryDt1.getValue() + ed_onDt_blk.getValue());
    if (chk_pda.getValue() == "1") {
      ds_ApplyAlloccar.setCellData(iRow, "pda", "Y");
      ds_ApplyAlloccar.setCellData(iRow, "sms", "Y");
    }
  }
  if (ds_fl.getCellData(lclRow, "repClntNo") == "000012" && ds_fl.getCellData(lclRow, "col1") != "Y") {
    var aaa = ed_qryDt1.getValue() + ws_onDt_blk.getValue();
    var bbb = ed_qryDt2.getValue() + ws_offDt_blk.getValue();
    if (flType == 'cargo') {
      if (ed_onQty_blk.getValue() == "" && ed_onWt_blkgetValue() == "") {
        $c.win.alert($p, "실상차 수량이나 실상차 중량을 입력하세요.").then(() => {
          ed_onQty_blk.focus();
        });
        return;
      }
      if (ed_onDt_blk.getValue() == "" || ed_offDt_blk.getValue() == "") {
        $c.win.alert($p, "시간을 모두 입력하세요");
        return;
      }
      if (aaa >= bbb) {
        $c.win.alert($p, "실하차일시는 실상차일시 이후여야 합니다.");
        return;
      }
    }
  }
  if (ds_fl.getCellData(lclRow, "col1") == "Y") {
    ds_ApplyAlloccar.removeAll();
    ds_ApplyAlloccar.reform();
    const iRow_col1Y = ds_ApplyAlloccar.insertRow();
    ds_ApplyAlloccar.setCellData(iRow_col1Y, "cond1", dlt_bottom.getCellData(vehclRow, "ez110Idx"));
    ds_ApplyAlloccar.setCellData(iRow_col1Y, "cond2", ds_fl.getCellData(lclRow, "dmWrkIndictNo"));
    if (await $c.win.confirm($p, "선매오더처리 하시겠습니까?")) {
      $c.sbm.execute($p, sbm_Preorder);
    }
  } else {
    if (await $c.win.confirm($p, "배차 하시겠습니까?")) {
      $c.sbm.execute($p, sbm_ApplyAlloccar);
    }
  }
};

/**
 * 선매오더 callback
 */
scwin.sbm_Preorder_submitdone = function (e) {
  if (e.responseJSON.resultDataSet[0].Code == 0) {
    const pFrame = opener.$p.getComponentById($c.data.getParameter($p).pFrame);
    $c.win.alert($p, "조회조건 저장에 성공하였습니다.").then(() => {
      pFrame.scope.scwin.reflashdata();
      window.close();
    });
  }
};

/**
 * 배차 callback
 */
scwin.sbm_ApplyAlloccar_submitdone = function (e) {
  if (scwin.f_addInfo()) {
    scwin.f_Save("SAVE");
  } else {
    const pFrame = opener.$p.getComponentById($c.data.getParameter($p).pFrame);
    if (e.responseJSON.resultDataSet[0].Code == 0) {
      const msg = ds_result.getCellData(0, "outMsg");
      if (!$c.util.isEmpty($p, msg)) {
        $c.win.alert($p, msg).then(() => {
          pFrame.scope.scwin.reflashdata();
          window.close();
        });
      }
    }
  }
};

/**
 * 출도착정보 입력 추가(동부제철의 경우만, 20120718 서근원)
 */
scwin.f_addInfo = function () {
  const {
    cCase,
    pFrame,
    sFrame
  } = $c.data.getParameter($p);
  const topFrame = opener.$p.getComponentById(pFrame).scope;
  var lclRow = topFrame.scwin.selectedLclRow; // 선택된 화물정보
  var flType = topFrame.scwin.CargoType; // 화물종류(벌크,컨테이너)

  if (topFrame.ds_fl.getCellData(lclRow, "repClntNo") == "000012") {
    if (flType == 'cargo') {
      // 벌크 화물(합적화물인 경우 출도착 보고가 같이 된다.)
      const dmCoshippingNo = topFrame.ds_fl.getCellData(lclRow, "dmCoshippingNo");
      if (dmCoshippingNo != "") {
        // 동일 합적번호 배열
        const matchArr = topFrame.ds_fl.getMatchedIndex("dmCoshippingNo", dmCoshippingNo, true);
        if (matchArr.length > 0) {
          ds_fl.setJSON(topFrame.ds_fl.getMatchedJSON("dmCoshippingNo", dmCoshippingNo, true));
        }
      } else {
        //합적되지 않은 화물
        ds_fl.setJSON([topFrame.ds_fl.getRowJSON(lclRow)]);
      }

      //데이타 셋팅 후 주문번호 Ascending 정렬                
      // ds_fl.SortExpr = "+idx";
      // ds_fl.Sort();

      if (ed_onDt_blk.getValue() != "" && ed_offDt_blk.getValue() == "") {
        scwin.RPTTYP = "2";
      }
      return true;
      // scwin.f_Save('SAVE');
    } else {
      // 컨테이너
      const rowJson = topFrame.ds_flc.getRowJSON(lclRow);
      ds_flc.setJSON([rowJson]);
      ed_cntrNo_cnt.setValue(rowJson.cntrNo);
      ed_sealNo_cnt.setValue(rowJson.cntrSealNo);
      return true;
      // scwin.f_Save('SAVE');

      // 컨테이너 번호가 없으면 입력 받고 있으면 수정 불가
      // 고객사 요청에 따라 컨테이너 번호 수정가능하도록 변경 8.11
      // to-be 로직으로 변경해둠 2026.03.30
      // if (ed_cntrNo_cnt.getValue() == "")
      //  ed_cntrNo_cnt.setReadOnly(false);
    }
  }
  return false;
};

/**
 * 출도착정보 입력 추가(동부제철의 경우만, 20120718 서근원)
 */
scwin.f_Save = function (type) {
  const {
    cCase,
    pFrame,
    sFrame
  } = $c.data.getParameter($p);
  const topFrame = opener.$p.getComponentById(pFrame).scope;
  const lclRow = topFrame.scwin.selectedLclRow; // 선택된 화물정보
  const flType = topFrame.scwin.CargoType; // 화물종류(벌크,컨테이너)
  let vFlIdxs;
  if (flType == "cargo") {
    for (let i = 0; i < ds_fl.getTotalRow(); i++) {
      const iRow = ds_PdaReport.insertRow();
      if (ed_onDt_blk.getValue() != "" && ed_offDt_blk == "") {
        // 상차보고
        ds_PdaReport.setCellData(iRow, "rtpTyp", "1");
      } else if (scwin.RPTTYP == "2") {
        // 하차보고
        ds_PdaReport.setCellData(iRow, "rtpTyp", "2");
      } else if (ed_onDt_blk.getValue() != "" && ed_offDt_blk.getValue() != "") {
        //상하차보고
        ds_PdaReport.setCellData(iRow, "rtpTyp", "3");
      } else {
        ds_PdaReport.setCellData(iRow, "rtpTyp", "3");
      }
      ds_PdaReport.setCellData(iRow, "flFlag", "1");
      if (i > 0) {
        // 합적화물일경우
        ds_PdaReport.setCellData(iRow, "realOnQty", 0);
        ds_PdaReport.setCellData(iRow, "realOnWt", 0);
      }
      ds_PdaReport.setCellData(iRow, "realOnQty", ed_onQty_blk.getValue());
      ds_PdaReport.setCellData(iRow, "realOnWt", ed_onWt_blk.getValue());
      if (type == "SAVE") {
        ds_PdaReport.setCellData(iRow, "realOndt", ed_qryDt1.getValue() + ed_onDt_blk.getValue());
        ds_PdaReport.setCellData(iRow, "realOffdt", ed_qryDt2.getValue() + ed_offDt_blk.getValue());
      }
      vFlIdxs = ds_fl.getCellData(i, "idx").split('-'); // 선택된 화물 idx
      ds_PdaReport.setCellData(iRow, "ez202Idx", vFlIdxs[0]);
      ds_PdaReport.setCellData(iRow, "dtlIdx", vFlIdxs[1]);
      ds_PdaReport.setCellData(iRow, "railroadAdptDstCd", lc_trans_type.getValue());
    }
  } else {
    // 컨테이너
    // 벌크화물 ds_fl의 repClntNo가 "000012"인 경우 타는 로직인데.. 컨테이너가 될 수가 있나?
  }
  $c.sbm.execute($p, sbm_PdaReport);
};
scwin.sbm_PdaReport_submitdone = function (e) {
  const pFrame = opener.$p.getComponentById($c.data.getParameter($p).pFrame);
  if (e.responseJSON.resultDataSet[0].Code == 0) {
    const msg = ds_result.getCellData(0, "outMsg");
    if (!$c.util.isEmpty($p, msg)) {
      $c.win.alert($p, msg).then(() => {
        pFrame.scope.scwin.reflashdata();
        window.close();
      });
    }
  }
};

/**
 * 샤시번호 info
 */
scwin.dma_udcVehclNo_onmodelchange = function (info) {
  const {
    key,
    oldValue,
    newValue
  } = info;
  if ($c.util.isEmpty($p, newValue)) {
    scwin.chassisVehclNoHidden = "";
    scwin.chassisVehclNo = "";
    scwin.chassisEqCd = "";
    scwin.chassisEqKndCd = "";
    return;
  }
  if (key == "commTxt1") {
    if (typeof dlt_parentSelected === "undefined") return;
    const {
      ez124Idx,
      vehclNo,
      eqCd,
      eqKndCd
    } = dlt_parentSelected.getRowJSON(0);
    scwin.chassisVehclNoHidden = ez124Idx;
    scwin.chassisVehclNo = vehclNo;
    scwin.chassisEqCd = eqCd;
    scwin.chassisEqKndCd = eqKndCd;
  }
};

/**
 * 벌크화물 info
 */
scwin.ds_fl_ondataload = function () {
  ds_fl.modifyAllStatus("C");
  tbx_totalCargo.setValue(ds_fl.getTotalRow());
};

/**
 * 컨테이너 info
 */
scwin.ds_flc_ondataload = function () {
  ds_flc.modifyAllStatus("C");
  tbx_totalCont.setValue(ds_flc.getTotalRow());
};

/**
 * 날짜 format
 */
scwin.format_date = function (val) {
  return $c.date.formatDateTime($p, val, "yyyy/MM/dd");
};

/**
 * 날짜 format
 */
scwin.format_dashToSlash = function (val) {
  return val != "" ? val.replace(/-/g, "/") : val;
};

/**
 * 시간
 */
scwin.format_HhMm = function (val) {
  return `${val.slice(0, 2)}:${val.slice(2, 4)}`;
};

/**
 * 컨테이너-취급료 청구처
 */
scwin.format_hndlCmisPl = function (val) {
  return val == "0.0" ? "0" : val;
};
